using Valora.Application.DTOs;
namespace Valora.Application.Contracts;
public interface IMigrationBatchRepository { Task<MigrationBatchDto> CreateAsync(string sourceType,string sourceName,string mode,string requestedBy,CancellationToken ct=default); Task<IReadOnlyList<MigrationBatchDto>> ListAsync(CancellationToken ct=default); Task<MigrationBatchDto?> GetAsync(Guid id,CancellationToken ct=default); Task UpdateStatusAsync(Guid id,string status,string summaryMaskedJson,CancellationToken ct=default); }
public interface IMigrationSourceFileRepository { Task<MigrationSourceFileDto> CreateAsync(Guid? batchId,string fileName,string? contentType,long sizeBytes,string sha256,string? storedPath,string status,CancellationToken ct=default); Task<IReadOnlyList<MigrationSourceFileDto>> ListAsync(CancellationToken ct=default); Task<MigrationSourceFileDto?> GetAsync(Guid id,CancellationToken ct=default); }
public interface IMigrationRecordRepository { Task AddAsync(MigrationRecordDto record,CancellationToken ct=default); Task<IReadOnlyList<MigrationRecordDto>> ListByBatchAsync(Guid batchId,CancellationToken ct=default); }
public interface IMigrationMappingRepository { Task AddAsync(MigrationMappingDto mapping,CancellationToken ct=default); Task<IReadOnlyList<MigrationMappingDto>> ListByBatchAsync(Guid batchId,CancellationToken ct=default); }
public interface IMigrationConflictRepository { Task AddAsync(MigrationConflictDto conflict,CancellationToken ct=default); Task<IReadOnlyList<MigrationConflictDto>> ListByBatchAsync(Guid batchId,CancellationToken ct=default); Task ResolveAsync(Guid conflictId,string resolution,string resolvedBy,CancellationToken ct=default); Task<bool> HasBlockingAsync(Guid batchId,CancellationToken ct=default); }
public interface IMigrationRollbackRepository { Task AddAsync(MigrationRollbackItemDto item,CancellationToken ct=default); Task<IReadOnlyList<MigrationRollbackItemDto>> ListByBatchAsync(Guid batchId,CancellationToken ct=default); Task MarkRolledBackAsync(Guid id,CancellationToken ct=default); }
